(function() {
  const ctx = document.getElementById('fundingChart').getContext('2d');
  new Chart(ctx, {
    type: 'bar',
    data: {
      labels: ['2021', '2022', '2023', '2024', '2025'],
      datasets: [
        {
          label: 'Funding ($B)',
          data: [114.9, 76.5, 65.6, 114.4, 225.8],
          backgroundColor: ['#9f7aea','#9f7aea','#9f7aea','#9f7aea','#6b21a8'],
          borderRadius: 6,
          yAxisID: 'y',
          order: 2
        },
        {
          label: 'Deals',
          data: [6085, 6148, 6065, 6934, 6913],
          type: 'line',
          borderColor: '#0a1f44',
          backgroundColor: 'transparent',
          borderWidth: 2.5,
          pointBackgroundColor: '#0a1f44',
          pointRadius: 4,
          tension: 0.2,
          yAxisID: 'y1',
          order: 1
        }
      ]
    },
    options: {
      animation: false,
      maintainAspectRatio: false,
      plugins: {
        legend: {
          position: 'top',
          labels: {
            font: { family: "system-ui, -apple-system, 'Segoe UI', sans-serif", size: 12 },
            usePointStyle: true,
            pointStyle: 'circle'
          }
        },
        tooltip: {
          callbacks: {
            label: function(context) {
              if (context.dataset.label === 'Funding ($B)') return 'Funding: $' + context.parsed.y + 'B';
              return 'Deals: ' + context.parsed.y.toLocaleString();
            }
          }
        }
      },
      scales: {
        y: {
          position: 'left',
          beginAtZero: true,
          max: 250,
          ticks: {
            callback: function(v) { return '$' + v + 'B'; },
            font: { size: 11 }
          },
          grid: { color: '#e2e8f0' },
          title: { display: true, text: 'Funding ($B)', font: { size: 12 } }
        },
        y1: {
          position: 'right',
          beginAtZero: true,
          max: 8000,
          ticks: {
            callback: function(v) { return v.toLocaleString(); },
            font: { size: 11 }
          },
          grid: { drawOnChartArea: false },
          title: { display: true, text: 'Deals', font: { size: 12 } }
        },
        x: {
          grid: { display: false },
          ticks: { font: { size: 12, weight: '600' } }
        }
      }
    }
  });
})();
